                    String userId = segments.get(1);
                    if (userId == null || userId.trim().isEmpty()) return new Intent(context, MainActivity.class);

                    Intent i = new Intent(context, ProfileActivity.class);
                    i.putExtra(ProfileActivity.EXTRA_USER_ID, userId);
